class NFA:
 def __init__(self, states, start, accept, transitions):
 self.states = states
 self.start = start
 self.accept = accept
 self.transitions = transitions

# Build NFA for single symbol 'a'
def symbol_nfa(symbol):
 s1, s2 = fresh_states(2)
 return NFA(
 states={s1, s2},
 start=s1,
 accept={s2},
 transitions={(s1, symbol): {s2}}
 )

# Build NFA for concatenation (a.b)
def concat_nfa(nfa1, nfa2):
 # Connect accept states of nfa1 to start of nfa2
 for s in nfa1.accept:
 nfa1.transitions[(s, 'ε')] = {nfa2.start}
 return NFA(
 states=nfa1.states | nfa2.states,
 start=nfa1.start,
 accept=nfa2.accept,
 transitions=nfa1.transitions | nfa2.transitions
 )

# Build NFA for union (a|b)
def union_nfa(nfa1, nfa2):
 new_start, new_accept = fresh_states(2)
 return NFA(
 states=nfa1.states | nfa2.states | {new_start, new_accept},
 start=new_start,
 accept={new_accept},
 transitions={
 (new_start, 'ε'): {nfa1.start, nfa2.start},
 (nfa1.accept, 'ε'): {new_accept},
 (nfa2.accept, 'ε'): {new_accept}
 }
 )

# Build NFA for Kleene star (a*)
def star_nfa(nfa):
 new_start, new_accept = fresh_states(2)
 # Add ε-transitions: start→accept, start→nfa.start, nfa.accept→accept, nfa.accept→nfa.start
 transitions = nfa.transitions.copy()
 transitions[(new_start, 'ε')] = {new_accept, nfa.start}
 for s in nfa.accept:
 transitions[(s, 'ε')] = {new_accept, nfa.start}
 return NFA(
 states=nfa.states | {new_start, new_accept},
 start=new_start,
 accept={new_accept},
 transitions=transitions
 )

