def complement(L, alphabet):
 all_strings = generate_all_strings(alphabet) // Σ*
 return all_strings - L // Set difference

def concatenation(L1, L2):
 result = set()
 for w1 in L1:
 for w2 in L2:
 result.add(w1 + w2)
 return result

def kleene_star(L):
 result = {''} // Start with epsilon
 # Keep adding concatenations until fixed point
 prev_size = 0
 while len(result) != prev_size:
 prev_size = len(result)
 result = result | concatenation(result, L)
 return result

